	.TITLE	ICONE	.PROC	M680002		; mnmonics CALM 2	.RADIX	10.		; base 10 par dfaut	.HEX			; listing en hexadcima	.REF	SM8		; df diverses	.REF	BIOS		; df bios	.REF	NTREL		; df noyau temps rel	.REF	GESMEM		; df gestionnaire de mmoire	.REF	FOS		; df file operating system	.REF	LIB		; df librairie	.REF	DRIVERS		; df drivers	.INS	ICODEF	.REV	3,42	.CODE	800,11,B'111,600,2000,300,2000,2,'*,0,0; Variables pour une macro; ------------------------	.LOC	0OLIMAC:	.BLKB	LBUEXE		; commande macro (+ paramtres)OPAMAC:	.BLKB	LBUEXE		; buffer pour un paramtreOPTMAC:	.BLKB	2		; ^relatif dans OBUMACOLGMAC:	.BLKB	2		; lg max dans OBUMACOCHMAC:	.BLKB	2		; canal fichier macroOBUMAC:	.BLKB	LGBLK		; buffer pour fichier macroLGZMAC:; Programme; ---------	.LOC	0START:	LIB	?OPELIB		; ouvre la librairie	LOAD.W	D3,#2		; D3 <-- souris par le clavier	LIB	?MOUSE		; utilise les 3 boutons souris	LOAD.L	A0,A3		; A0 <-- ^ligne de commande	LOAD.L	D4,#LGVAR	LOAD.W	D1,#MTYPCP	GESMEM	?GETMEM		; demande mmoire pour var.	JUMP,NE	FATERR	LOAD.L	A6,A4		; A6 <-- ^variables10$:	CLR.B	(A4+)		; variables <-- zro	DEC.L	D4	JUMP,NE	10$	NTREL	?GETMACHINE	RL.L	D4,#8	LOAD.B	(A6)+OMACHINE,D4	LOAD.L	A4,#R16"NAMDEF	LOAD.B	(A4)+0,(A3)+0	; NAMDEF <-- "100"/"SYS"	LOAD.B	(A4)+1,(A3)+1	LOAD.B	(A4)+2,(A3)+2	LOAD.L	A3,#(A6)+OBUDIS	LOAD.B	(A3)+0,#LOADGC	LOAD.B	(A3)+1,#'N	LOAD.B	(A3)+2,#'E!2^7	LOAD.B	(A3)+3,#11	; charge NEF11	COMP.B	(A6)+OMACHINE,#SMAKY8	JUMP',EQ 30$	LOAD.B	(A3)+3,#07	; charge NEF0730$:	LOAD.W	D3,#4	LIB	?STRING		; charge le gencar	JUMP,NE FATERR	LOAD.B	(A3)+0,#USEGC	LIB	?STRING		; utilise le gencar	JUMP,NE FATERR	LOAD.L	A3,A0		; A3 <-- ^ligne de commande	LOAD.L	A4,#(A6)+ONAMEI	LIB	?SKPNAM		; A3 <-- cherche nom aprs "ICONE"	JUMP',EQ 20$		; dans la ligne de commande	LOAD.L	A3,#R16"NAMDEF20$:	LOAD.B	D3,(A3+)	JUMP',EQ 25$	COMP.B	D3,#CR	JUMP',EQ 25$	COMP.B	D3,#SPACE	JUMP',EQ 25$	COMP.B	D3,#'/	JUMP',EQ 25$	LOAD.B	(A4+),D3	JUMP	20$25$:	CLR.B	(A4)	LOAD.L	A3,#(A6)+ONAMEI	LOAD.L	A4,#R16"EXTDEF	CLR.W	D3	LIB	?ADDEXT		; ajoute .ICONE si pas d'autre extension	LOAD.W	(A6)+OHISTI,#-1	; pas encore d'histoire	CALL	AFMENU		; affiche le bon menu	LIB	?GCHKEY		; D6 <-- canal du clavier	LOAD.W	(A6)+OCHKEY,D6	CALL	INIDEF		; lit ICONE.LIST	JUMP,NE	FATERR	CALL	INIDIS		; init paramtres display	JUMP,NE	FATERR	LOAD.B	D3,#EOP	LIB	?AFCAR		; efface toute la fentre	.INS	ICOMAIN	.INS	ICOMACROQUITTE:	LOAD.B	D3,#EOP	LIB	?AFCAR		; efface toute la fentreFATERR:	LIB	?CLOLIB		; ferme la librairie	FOS	?STOP		; avorte le processus ...; Insertion des zones dtectes; -----------------------------;--------\; FRAPPE  >;========/; Frappe quelques caractres en fonction de l'icone ou du; fichier slectionn.; in	D3.B		zro => liste fichiers ncessaire;	(A6)+OLSTII.W	rang de l'icone  frapper; out	D7.W		zro  => fini;			autre => pas fini; mod	D4.W, D7.WFRAPPE:	INC.W	(A6)+OHISTL	; monte dans l'arbre	TEST.B	(A6)+OFLAGS:#BICONE	JUMP,BS	FLICONE	TEST.B	(A6)+OFLAGS:#BLIST	JUMP,BC	FICONE	TEST.B	(A6)+OFLAGS:#BTEXT	JUMP,BS	FTEXT	JUMP	FFICHIER;--------\; FICONE  >;--------/; Frappe un nom de programme en fonction de l'icone ; slectionn.; in	D3.B		zro => liste fichiers ncessaire;	(A6)+OLSTII.W	rang de l'icone  frapper; out	(A6)+OMEMII.W	rang de l'icone frapp;	D7.W		zro  => fini;			autre => pas fini; mod	D4.W, D7.WFICONE:	PUSHM.L	D0,D2,D3,D4,A3,A4	LOAD.B	D0,D3		; D0 <-- liste ncessaire ?	LOAD.W	D4,(A6)+OLSTII	; D4 <-- icone slectionn	LOAD.W	(A6)+OMEMII,D4	CALL	SYNSRC		; A4 <-- ^dfinition corresp.	JUMP',NE 90$	EX.L	A3,A4	LIB	?SKPNAM		; A4 <-- saute le numro	EX.L	A4,A3	JUMP',NE 90$		; si rien aprs => 90$	CLR.B	(A6)+OBUEXE	; ligne de commande vide	CALL	EXCOMM		; excute une commande90$:	CALL	AFCOMM		; affiche la commande	POPM.L	D0,D2,D3,D4,A3,A4	TEST.W	D7		; retour EQ/NE	RET;--------\; EXCOMM  >;========/; Excute une commande LIST ou ICONE prcde ventuellement; d'une chane  insrer.; in	A4.L	^["car"] [mot-clef commande];	D0.B	zro  => liste ncessaire; out	D7.W	zro  => fini;		autre => pas fini; mod	D7.WEXCOMM:	PUSHM.L	D2,D3,A3,A4	CLR.W	D7		; D7 <-- fini	COMP.B	(A4),#'"	; chane  insrer ?	JUMP,NE	40$		; non => 40$				; oui =>	CALL	GETLAST		; D3 <-- dernier caractre frapp	COMP.B	D3,#CARMARK	; dj termin par une marque ?	JUMP',NE 10$		; non => 10$	CALL	DETRUIT		; oui => enlve-la10$:	INC.L	A4		; A4 <-- saute le 1er guillement	CLR.B	D2		; D2 <-- dernier car. frapp20$:	LOAD.B	D3,(A4+)	JUMP,EQ	90$	COMP.B	D3,#CR	JUMP,EQ	90$	COMP.B	D3,#'"		; fin commande ?	JUMP',EQ 30$	COMP.B	D3,#'|	JUMP',EQ 25$	CALL	INSERT		; "frappe" un caractre	LOAD.B	D2,D3		; D2 <-- dernier car. frapp	JUMP	20$25$:	LOAD.B	D2,#SPACE	; si "blabla|" => n'ajoute pas espace	JUMP	20$30$:	COMP.B	D2,#SPACE	; espace frapp en dernier ?	JUMP',EQ 32$		; oui => 32$	LOAD.B	D3,#SPACE	; non =>	CALL	INSERT		; "frappe" un espace32$:	LOAD.B	D3,#CARMARK	CALL	INSERT		; insre une marque35$:	LOAD.B	D3,(A4+)	JUMP,EQ	90$	COMP.B	D3,#CR	JUMP,EQ	90$	COMP.B	D3,#SPACE	JUMP,EQ	35$	COMP.B	D3,#TAB	JUMP,EQ	35$	DEC.L	A4		; A4 <-- ^mot-clef40$:	LOAD.B	D3,(A4)		; D3 <-- 1re lettre commande	LIB	?MINMAJ		; D3 <-- lettre majuscule	COMP.B	D3,#'L		; LIST ?	JUMP',EQ 60$		; oui => 60$	COMP.B	D3,#'T		; TEXT ?	JUMP',EQ 65$		; oui => 65$	COMP.B	D3,#'I		; ICONE ?	JUMP',EQ 70$		; oui => 70$	JUMP'	90$60$:	CALL	EXLIST	JUMP'	90$65$:	CALL	EXTEXT	JUMP'	90$70$:	CALL	EXICONE;	JUMP'	90$90$:	POPM.L	D2,D3,A3,A4	TEST.W	D7		; retour EQ/NE	RET;--------\; EXLIST  >;--------/; LIST: Affiche une liste de fichiers.; in	A4.L	^mot-clef LIST;	D0.B	zro => liste ncessaire; out	D7.W	zro  => fini;		autre => pas fini; mod	D7.WEXLIST:	PUSHM.L	D3,D4,A4	CLR.W	D740$:	LOAD.B	D3,(A4+)	; cherche dbut critre	JUMP,EQ	90$	COMP.B	D3,#CR	JUMP,EQ	90$	COMP.B	D3,#']	JUMP,EQ	90$	COMP.B	D3,#'"		; dbut critre ?	JUMP,NE	40$		; non => 40$	LOAD.L	A3,A4		; A3 <-- ^dbut critre45$:	LOAD.B	D3,(A4+)	; cherche fin critre	JUMP,EQ	90$	COMP.B	D3,#CR	JUMP,EQ	90$	COMP.B	D3,#']	JUMP,EQ	90$	COMP.B	D3,#'"		; fin critre ?	JUMP,NE	45$		; non => 45$50$:	LOAD.B	D3,(A4+)	; cherche dbut dfaut	JUMP',EQ 60$	COMP.B	D3,#CR	JUMP',EQ 60$	COMP.B	D3,#']	JUMP',EQ 60$	COMP.B	D3,#'"		; dbut dfaut ?	JUMP,NE	50$		; non => 50$60$:	DEC.L	A4		; A4 <-- ^guillemet/terminateur	TEST.B	D0		; liste ncessaire ?	JUMP,NE	80$		; non => 80$	CALL	AFCOMM		; affiche la commande	CALL	AFLIST		; affiche la liste ...	COMP.W	D7,#1		; excution immdiate ?	JUMP',EQ 70$		; oui => 70$	COMP.W	(A6)+OSRCNN,#2	; au moins deux fichiers ?	JUMP',LO 75$		; non => 75$	LOAD.W	D4,(A6)+OLSTII	CALL	INVERSE		; montre un fichier	LOAD.W	D7,#1		; D7 <-- pas fini (manque file)	JUMP	90$70$:	LIB	?IFMOUSE	; D4 <-- position de la souris	JUMP',NE 80$	CALL	DETECTE		; cherche o est la souris	JUMP',NE 80$		; si pas dans qq chose => 80$	LOAD.W	(A6)+OLSTII,D4	CALL	INVERSE		; dessine icone/fichier slectionn	LOAD.B	D3,#1		; D3 <-- excution immdiate	CALL	FRAPPE		; frappe tout de suite	JUMP'	80$75$:	TEST.W	(A6)+OSRCNN	; au moins un fichier ?	JUMP',EQ 80$		; non => 80$	PUSH.W	(A6)+OLSTII	CLR.W	(A6)+OLSTII	; slectionne le seul existant	CALL	FFICHIER	; "frappe" le premier fichier	POP.W	(A6)+OLSTII80$:	CLR.W	D7		; D7 <-- ok (c'est fini)90$:	POPM.L	D3,D4,A4	TEST.W	D7		; retour EQ/NE	RET;--------\; EXTEXT  >;--------/; TEXT: Affiche une liste de textes.; in	A4.L	^mot-clef TEXT;	D0.B	zro  => liste ncessaire; out	D7.W	zro  => fini;		autre => pas fini; mod	D7.WEXTEXT:	PUSHM.L	D3,D4,A4	EX.L	A3,A4	LIB	?SKPNAM		; A4 <-- saute mot-clef	EX.L	A4,A3	TEST.B	D0		; liste ncessaire ?	JUMP',NE 80$		; non => 80$	CALL	AFCOMM		; affiche la commande	CALL	AFTEXT		; affiche les textes ...	COMP.W	D7,#1		; excution immdiate ?	JUMP',EQ 80$		; oui => 80$	COMP.W	(A6)+OSRCNN,#2	; au moins deux textes ?	JUMP',LO 75$		; non => 75$	LOAD.W	D4,(A6)+OLSTII	CALL	INVERSE		; montre un texte	LOAD.W	D7,#1		; D7 <-- pas fini (manque file)	JUMP'	90$75$:	TEST.W	(A6)+OSRCNN	; au moins un texte ?	JUMP',EQ 80$		; non => 80$	PUSH.W	(A6)+OLSTII	CLR.W	(A6)+OLSTII	; slectionne le seul existant	CALL	FLICONE		; "frappe" le premier texte	POP.W	(A6)+OLSTII80$:	CLR.W	D7		; D7 <-- ok (c'est fini)90$:	POPM.L	D3,D4,A4	TEST.W	D7		; retour EQ/NE	RET;--------\; EXICONE >;--------/; ICONE: Affiche une liste d'icones.; in	A4.L	^mot-clef ICONE;	D0.B	zro => liste ncessaire; out	D7.W	zro  => fini;		autre => pas fini; mod	D7.WEXICONE:	PUSHM.L	D3,D4,A4	EX.L	A3,A4	LIB	?SKPNAM		; A4 <-- saute mot-clef	EX.L	A4,A3	TEST.B	D0		; liste ncessaire ?	JUMP',NE 80$		; non => 80$	CALL	AFCOMM		; affiche la commande	CALL	AFLICONE	; affiche les icones ...	COMP.W	D7,#1		; excution immdiate ?	JUMP',EQ 80$		; oui => 80$	COMP.W	(A6)+ONBIC,#2	; au moins deux icones ?	JUMP',LO 75$		; non => 75$	COMP.W	(A6)+OHISTL,#1	; premier niveau ?	JUMP',NE 40$		; non => 40$	LOAD.W	(A6)+OHISTI,(A6)+OMEMII ; oui => mmorise l'histoire40$:	LOAD.W	D4,(A6)+OLSTII	CALL	INVERSE		; montre un icone	LOAD.W	D7,#1		; D7 <-- pas fini (manque file)	JUMP'	90$75$:	TEST.W	(A6)+ONBIC	; au moins un icone ?	JUMP',EQ 80$		; non => 80$	PUSH.W	(A6)+OLSTII	CLR.W	(A6)+OLSTII	; slectionne le seul existant	CALL	FLICONE		; "frappe" le premier icone	POP.W	(A6)+OLSTII80$:	CLR.W	D7		; D7 <-- ok (c'est fini)90$:	POPM.L	D3,D4,A4	TEST.W	D7		; retour EQ/NE	RET;---------\; FLICONE  >;---------/; Frappe un nom en fonction de l'icone slectionn  la fin; de la ligne de commande.; in	(A6)+OLSTII.W	rang de l'icone  frapper;	(A6)+OPTNIC.L	^numros;	(A6)+OPTLIC.L	^noms; out	(A6)+OMEMLI.n	numro de l'icone frapp;	D7.W		zro  => fini;			autre => pas fini; mod	D4.W, D7.WFLICONE:	PUSHM.L	D0,D2,D3,D4,A3,A4,A5	LOAD.L	A3,#(A6)+OBUEXE	; A3 <-- ^commande actuelle	CLR.W	D7		; D7 <-- fini05$:	LOAD.B	D3,(A3+)	JUMP',EQ 10$	COMP.B	D3,#CARMARK	JUMP,NE	05$	TEST.B	(A3)		; qq chose aprs la marque ?	JUMP,NE	90$		; oui => 90$ (n'ajoute rien)10$:	LOAD.L	A4,(A6)+OPTNIC	; A4 <-- ^numros	LOAD.L	A3,(A6)+OPTLIC	; A3 <-- ^noms	LOAD.W	D4,(A6)+OLSTII	; D4 <-- icone slectionn	COMP.W	D4,#-1	JUMP,EQ	90$20$:	TEST.W	D4		; rang atteint ?	JUMP',EQ 30$		; oui => 30$	DEC.W	D4	EX.L	A3,A4	LIB	?SKPNAM		; A4 <-- ^numro suivant	EX.L	A4,A3	CALL	SKPNAME		; A3 <-- ^nom suivant	JUMP	20$30$:	LOAD.L	A5,#(A6)+OMEMLI	; A5 <-- ^buffer pour mm .choix35$:	LOAD.B	D3,(A4+)	JUMP',EQ 38$	COMP.B	D3,#CR	JUMP',EQ 38$	COMP.B	D3,#SPACE	JUMP',EQ 38$	LOAD.B	(A5+),D3	; mmorise le numro (en ASCII)	JUMP	35$38$:	CLR.B	(A5)		; termine le numro	LOAD.L	A4,A3	COMP.B	(A4),#'[	; commande ?	JUMP',NE 60$		; non => 60$				; oui =>	INC.L	A4		; A4 <-- saute le "["	CLR.B	D0		; D0 <-- liste ncessaire	CALL	EXCOMM		; excute la commande entre [ ]	JUMP'	90$60$:	COMP.B	(A4),#'"	; chane ?	JUMP',NE 90$		; non => 90$				; oui =>	INC.L	A4		; A4 <-- saute le guillemet65$:	LOAD.B	D3,(A4+)	JUMP',EQ 90$	COMP.B	D3,#CR	JUMP',EQ 90$	COMP.B	D3,#'"	JUMP',EQ 90$	CALL	INSERT		; commande <-- nom de fichier	JUMP	65$90$:	CALL	AFCOMM		; affiche la commande	POPM.L	D0,D2,D3,D4,A3,A4,A5	TEST.W	D7		; retour EQ/NE	RET;---------\; FTEXT    >;---------/; Frappe un nom en fonction du texte slectionn  la fin; de la ligne de commande.; in	(A6)+OLSTII.W	rang du texte  frapper;	(A6)+OPTNIC.L	^textes;	(A6)+OPTLIC.L	^noms; out	D7.W		zro  => fini;			autre => pas fini; mod	D4.W, D7.WFTEXT:	PUSHM.L	D0,D2,D3,D4,A3,A4,A5	LOAD.L	A3,#(A6)+OBUEXE	; A3 <-- ^commande actuelle	CLR.W	D7		; D7 <-- fini05$:	LOAD.B	D3,(A3+)	JUMP',EQ 10$	COMP.B	D3,#CARMARK	JUMP,NE	05$	TEST.B	(A3)		; qq chose aprs la marque ?	JUMP,NE	90$		; oui => 90$ (n'ajoute rien)10$:	LOAD.L	A3,(A6)+OPTLIC	; A3 <-- ^noms	LOAD.W	D4,(A6)+OLSTII	; D4 <-- texte slectionn	COMP.W	D4,#-1	JUMP,EQ	90$20$:	TEST.W	D4		; rang atteint ?	JUMP',EQ 30$		; oui => 30$	DEC.W	D4	CALL	SKPNAME		; A3 <-- ^nom suivant	JUMP	20$30$:	LOAD.L	A4,A3	COMP.B	(A4),#'[	; commande ?	JUMP',NE 60$		; non => 60$				; oui =>	INC.L	A4		; A4 <-- saute le "["	CLR.B	D0		; D0 <-- liste ncessaire	CALL	EXCOMM		; excute la commande entre [ ]	JUMP'	90$60$:	COMP.B	(A4),#'"	; chane ?	JUMP',NE 90$		; non => 90$				; oui =>	INC.L	A4		; A4 <-- saute le guillemet65$:	LOAD.B	D3,(A4+)	JUMP',EQ 90$	COMP.B	D3,#CR	JUMP',EQ 90$	COMP.B	D3,#'"	JUMP',EQ 90$	CALL	INSERT		; commande <-- nom de fichier	JUMP	65$90$:	CALL	AFCOMM		; affiche la commande	POPM.L	D0,D2,D3,D4,A3,A4,A5	TEST.W	D7		; retour EQ/NE	RET;---------\; FFICHIER >;---------/; Frappe un nom en fonction du fichier slectionn  la fin; de la ligne de commande.; in	(A6)+OLSTII.W	rang du fichier  frapper; out	(A6)+OMEMFI.n	nom du fichier frapp;	D7.W		zro  => fini;			autre => pas fini; mod	D4.W, D7.WFFICHIER:	PUSHM.L	D3,D4,A3,A4,A5	LOAD.L	A3,#(A6)+OBUEXE	; A3 <-- ^commande actuelle05$:	LOAD.B	D3,(A3+)	JUMP',EQ 10$	COMP.B	D3,#CARMARK	JUMP,NE	05$	TEST.B	(A3)		; qq chose aprs la marque ?	JUMP',NE 90$		; oui => 90$ (n'ajoute rien)10$:	LOAD.W	D4,(A6)+OLSTII	; D4 <-- fichier slectionn	CALL	LSTSRC		; A4 <-- ^nom du fichier	JUMP',NE 90$	LOAD.B	D3,(A4)		; D3 <-- 1er caractre fichier/dfaut	COMP.B	D3,#'@	JUMP',EQ 30$	COMP.B	D3,#'#	JUMP',EQ 30$	COMP.B	D3,#'0	JUMP',LO 90$	COMP.B	D3,#'9	JUMP',LS 30$	COMP.B	D3,#'A	JUMP',LO 90$	COMP.B	D3,#'Z	JUMP',HI 90$30$:	LOAD.L	A5,#(A6)+OMEMFI40$:	LOAD.B	D3,(A4+)	JUMP',EQ 50$	COMP.B	D3,#CR	JUMP',EQ 50$	COMP.B	D3,#'"	JUMP',EQ 50$	CALL	INSERT		; commande <-- nom de fichier	LOAD.B	(A5+),D3	; mmorise le nom du fichier	JUMP	40$50$:	CLR.B	(A5)		; termine la mmorisation90$:	CALL	AFCOMM		; affiche la commande	CLR.W	D7		; D7 <-- toujours ok	POPM.L	D3,D4,A3,A4,A5	TEST.W	D7		; retour EQ/NE	RET; Modules; -------	.INS	ICOAFF		; affichage	.INS	ICOLIST		; recherche dans SYS_LIST	.INS	ICOCOMM		; commandes	.INS	ICOMISC		; routines diverses; Textes; ------NAMDEF:	.ASCIZ	"???_TEXT.ICONE"NAMLST:	.ASCIZ	"SYS_LIST"NAMDI0:	.ASCIZ	"$DIS_0"NAMDIH:	.ASCIZ	"$DIS_8"TXMM0:	.ASCIZ	" #mm0:"TXMM1:	.ASCIZ	" #mm1:"TXMM2:	.ASCIZ	" #mm2:"EXTDEF:	.ASCIZ	".ICONE"LSTTERM:.B	0,CR,SPACE,'/,'",-1TKMENC:	.B	F5	.ASCIZ	"Assgc "	.B	F5+SHIFT	.ASCIZ	"Memgc "	.B	F6	.ASCIZ	"Mem "	.B	F7	.ASCIZ	"Command "	.B	F7+SHIFT	.ASCIZ	"Format "	.B	F8	.ASCIZ	"Halt "	.B	F9	.ASCIZ	"Cache "	.B	F9+SHIFT	.ASCIZ	"Uncache "	.B	F10	.ASCIZ	"Install "	.B	F10+SHIFT	.ASCIZ	"Deinstall "	.B	F11	.ASCIZ	"Assign "	.B	F11+SHIFT	.ASCIZ	"Deassign "	.B	F12	.ASCIZ	"Rep "	.B	F13	.ASCIZ	"Dir "	.B	F13+SHIFT	.ASCIZ	"Rel "	.B	F14	.ASCIZ	"Enter "	.B	F14+SHIFT	.ASCIZ	"Release "	.B	F15	.ASCIZ	"Arrt "	.B	0TXMEIC:	.ASCIZ	""	.ASCIZ	""	.ASCIZ	""	.ASCIZ	"Dbut  Fin       ";		!     !     !     !	.ASCIZ	""	.ASCIZ	"Haut"	.ASCIZ	""	.ASCIZ	"Bas"	.ASCIZ	""	.ASCIZ	"Gauche"	.ASCIZ	""	.ASCIZ	"Droite"TXMEIS:	.ASCIZ	""	.ASCIZ	"Stop"	.ASCIZ	""	.ASCIZ	"Dbut  Fin       ";		!     !     !     !	.ASCIZ	""	.ASCIZ	"Haut"	.ASCIZ	""	.ASCIZ	"Bas"	.ASCIZ	""	.ASCIZ	"Gauche"	.ASCIZ	""	.ASCIZ	"Droite"TXMECC:	.ASCIZ	""	.ASCIZ	""	.ASCIZ	""	.ASCIZ	"";		|     |     |     |	.ASCIZ	"      Memgc      "	.ASCIZ	"      Assgc  Mem ";		|     |     |     |	.ASCIZ	"Forma.      Uncac"	.ASCIZ	"Comma. Halt Cache";		|     |     |     |	.ASCIZ	"Deins.Deass.     "	.ASCIZ	"Insta.Assig. Rep ";		|     |     |     |	.ASCIZ	" Rel  Relea.     "	.ASCIZ	" Dir  Enter Arrt";		|     |     |     |TXMECS:	.ASCIZ	""	.ASCIZ	"Stop"	.ASCIZ	""	.ASCIZ	"";		|     |     |     |	.ASCIZ	"      Memgc      "	.ASCIZ	"      Assgc  Mem ";		|     |     |     |	.ASCIZ	"Forma.      Uncas"	.ASCIZ	"Comma. Halt Cash ";		| 